"use client";

import { motion, useReducedMotion } from "framer-motion";

export default function FoldingIndexTransition() {
  const reduced = useReducedMotion();
  return <motion.section whileHover={reduced ? undefined : { y: -2 }} transition={{ duration: .18 }} className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-sm"><p className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">numbered route fold</p><h2 className="mt-2 text-2xl font-black text-[#111]">Folding Index Transition</h2><motion.div initial={{ opacity: .55 }} whileHover={{ opacity: 1, x: reduced ? 0 : 4 }} transition={reduced ? { duration: .12 } : { type: "spring", stiffness: 320, damping: 28 }} className="mt-5 rounded-2xl bg-[#f4f5f6] p-4 text-sm font-bold text-[#111]">Focused state ready</motion.div><button type="button" className="mt-4 min-h-11 rounded-xl bg-[#111] px-4 text-sm font-bold text-white outline-offset-4 focus-visible:outline focus-visible:outline-2 focus-visible:outline-[#111]">Inspect pattern</button><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">Keyboard-ready interactive preview.</p></motion.section>;
}
